import { Injectable } from '@angular/core';
import { AngularFirestore, AngularFirestoreCollection, QuerySnapshot } from '@angular/fire/firestore';
import { throwError } from 'rxjs';
import { catchError, map } from 'rxjs/operators';
import { AuthService } from '../auth/auth.service';
import { UserService } from '../user/user.service';
import firebase from 'firebase';
import { QRService } from '../qr/qr.service';
import { async } from 'rxjs/internal/scheduler/async';

export interface Scan {
  id: string;
  productId: string;
  brandId: string;
  isRegistered: boolean;
  latitude: number;
  longitude: number;
  time: number;
}

@Injectable({
  providedIn: 'root',
})
export class StatsService {
  
  constructor(private angularFirestore: AngularFirestore, 
    public authService: AuthService, 
    public userService: UserService,
    public qrService: QRService,
  ) {
  }

  getUserScans() {
    const brandIds = this.authService.getUser().adminBrands;
    return this.angularFirestore.collection("scans", ref => ref.where(new firebase.firestore.FieldPath("brandId"), 'in', brandIds))
      .get().pipe(
        map((docs: QuerySnapshot<any>) => {
          return docs.docs.map(e => {
            return {
              ...e.data(),
              id: e.id
            } as Scan;
          });
        })
    );
  }

  getBrandScans(brandId: string) {
    return this.angularFirestore.collection("scans", ref => ref.where(new firebase.firestore.FieldPath("brandId"), '==', brandId))
      .get().pipe(
        map((docs: QuerySnapshot<any>) => {
          return docs.docs.map(e => {
            return {
              ...e.data(),
              id: e.id
            } as Scan;
          });
        })
    );
  }
}
